const SUPABASE_URL = 'https://wddatxgqhdiosuhcztex.supabase.co';
const BUCKET = 'app-assets';

// assetMode controls which asset types are generated.
// 'avatars'     → only avatar rows (8 items: 4 chars × 2 frames)
// 'backgrounds' → only background rows (future)
// 'all'         → everything
const ASSET_MODE = 'avatars';

return [{
  json: {
    supabaseUrl: SUPABASE_URL,
    bucket: BUCKET,
    assetMode: ASSET_MODE,
    style: 'Soft pastel Japanese kawaii manga style for children aged 6-12. Bright warm colors, rounded shapes, friendly and magical atmosphere. No text, no typography, no speech bubbles.',
    brandColors: {
      primary:    '#FF8A65',
      background: '#FFFCF5',
      secondary:  '#7EC8E3',
      fantasy:    '#C8A2C8',
      space:      '#7EC8E3',
      ocean:      '#4FC3F7'
    }
  }
}];

const cfg = $input.first().json;
const S   = cfg.style;
const c   = cfg.brandColors;
const mode = cfg.assetMode || 'avatars';

const AVATARS = [
  {
    character_name: 'Kaito Explorateur',
    gender: 'boy',
    display_order: 1,
    storage_prefix: 'avatars/boy-explorer',
    base_prompt: `${S}\n\nCreate a cute chibi-style avatar portrait of a brave boy explorer, aged 8.\n\nCHARACTER: Messy brown hair, big bright amber eyes, adventure hat slightly tilted, blue explorer vest with star patches, small compass around neck.\n\nFRAMING: Head and shoulders, centered, circular composition.\nBACKGROUND: Transparent or soft warm gradient (${c.primary} to ${c.background}).`,
    frames: {
      normal: 'Expression: confident and friendly smile. Must make a child want to pick this avatar.',
      happy:  'Expression: wide beaming smile, eyes crinkling with joy, slight head tilt. Radiating excitement and warmth.'
    }
  },
  {
    character_name: 'Ryu Magicien',
    gender: 'boy',
    display_order: 2,
    storage_prefix: 'avatars/boy-wizard',
    base_prompt: `${S}\n\nCreate a cute chibi-style avatar portrait of a young boy wizard, aged 7.\n\nCHARACTER: Spiky dark blue hair, large curious violet eyes, tiny round glasses, oversized purple wizard hat with a golden star, blue robe with sparkle patterns, holding a small glowing wand.\n\nFRAMING: Head and shoulders, centered, circular composition.\nBACKGROUND: Transparent or soft purple gradient (${c.fantasy} to ${c.background}).`,
    frames: {
      normal: 'Expression: wonder and excitement. Magical sparkles around him.',
      happy:  'Expression: huge delighted grin, eyes sparkling, wand glowing brighter. Surrounded by swirling golden stars.'
    }
  },
  {
    character_name: 'Luna Fée',
    gender: 'girl',
    display_order: 1,
    storage_prefix: 'avatars/girl-fairy',
    base_prompt: `${S}\n\nCreate a cute chibi-style avatar portrait of a magical fairy girl, aged 8.\n\nCHARACTER: Long flowing pink hair with tiny flowers woven in, large sparkling green eyes, delicate translucent butterfly wings, flower crown with soft glow, pastel pink dress with petal layers, tiny star freckles on cheeks.\n\nFRAMING: Head and shoulders, centered, circular composition.\nBACKGROUND: Transparent or soft pink gradient (${c.primary} to ${c.background}).`,
    frames: {
      normal: 'Expression: gentle and magical smile. Sparkles and tiny hearts floating around.',
      happy:  'Expression: overjoyed laugh, eyes lit up, wings shimmering faster. Pink sparkles and hearts exploding around her.'
    }
  },
  {
    character_name: 'Mei Pirate',
    gender: 'girl',
    display_order: 2,
    storage_prefix: 'avatars/girl-pirate',
    base_prompt: `${S}\n\nCreate a cute chibi-style avatar portrait of a brave pirate girl, aged 9.\n\nCHARACTER: Short wavy red hair, big confident teal eyes, cute tiny pirate hat with a heart skull, red bandana, striped shirt, small golden anchor necklace, one tiny star-shaped earring.\n\nFRAMING: Head and shoulders, centered, circular composition.\nBACKGROUND: Transparent or soft ocean gradient (${c.ocean} to ${c.background}).`,
    frames: {
      normal: 'Expression: bold and playful grin. Small waves and stars around.',
      happy:  'Expression: triumphant laugh, fist pumped, eyes gleaming. Confetti and tiny anchors flying around her.'
    }
  }
];

if (mode !== 'avatars' && mode !== 'all') {
  return [];
}

const items = [];
for (const avatar of AVATARS) {
  for (const [frame_type, frame_desc] of Object.entries(avatar.frames)) {
    items.push({
      json: {
        character_name: avatar.character_name,
        frame_type:     frame_type,
        gender:         avatar.gender,
        display_order:  avatar.display_order,
        storage_path:   `${avatar.storage_prefix}-${frame_type}.png`,
        bucket:         cfg.bucket,
        supabaseUrl:    cfg.supabaseUrl,
        prompt:         `${avatar.base_prompt}\n\n${frame_desc}`
      }
    });
  }
}

return items;

// Gemini replaces $json — reach back to the source item via item pairing
const meta = $('Build Avatar Items').item.json;

const image_url = `${meta.supabaseUrl}/storage/v1/object/public/${meta.bucket}/${meta.storage_path}`;

return [{
  json: {
    character_name: meta.character_name,
    frame_type:     meta.frame_type,
    image_url:      image_url,
    storage_path:   meta.storage_path,
    gender:         meta.gender,
    display_order:  meta.display_order
  }
}];

const meta = $('Build Avatar Items').item.json;
console.log('SKIP - Gemini failed for:', meta.character_name, meta.frame_type);
return [{ json: { skipped: true, character_name: meta.character_name, frame_type: meta.frame_type } }];
